import { pollSource, filterBy, sendSlackMessage } from './utils';

async function main() {
  for await (const articles of pollSource('https://example.com/feed.xml', 60000)) {
    const matching = filterBy(articles, (a) => a.title.includes('AI'));
    for (const article of matching) {
      await sendSlackMessage('#ai-news', article.title);
    }
  }
}

import { validateSchema, normalizeFields, writeToDB } from './utils';

async function handlePayload(payload: unknown) {
  const [validation, normalized] = await Promise.all([
    validateSchema(payload),
    normalizeFields(payload),
  ]);
  const merged = { ...normalized, _validation: validation };
  await writeToDB('ingested_data', merged);
}

import { sendPushNotification } from './utils';

const WINDOW_SIZE = 10;
const readings: number[] = [];

async function onSensorReading(temp: number) {
  readings.push(temp);
  if (readings.length > WINDOW_SIZE) readings.shift();

  const avg = readings.reduce((sum, r) => sum + r, 0) / readings.length;

  if (avg > 80) {
    await sendPushNotification(`Temperature alert: avg ${avg.toFixed(1)}°F exceeds 80°F`);
  }
}
